def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 7:
            acc = 0
            for a in range(7, 0, -1):
                for b in range(a, a + 5):
                    acc += ((ratio - a) ** 4) * np.sin(ratio * b / (a + 0.7)) / (a + b + 1)
            priority = acc * np.exp(ratio / 10)
            priority += np.tanh(ratio) * 15
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 10
        elif 4 < ratio <= 7:
            base = 0
            for c in range(1, int(np.floor(ratio)) + 4):
                for d in range(1, c + 5):
                    base += np.cos(ratio * c * 0.6) * ((ratio - c) ** 2) / (d + 0.8)
            penalty = np.sin(ratio * 3) * 8 - np.log(ratio) * 5
            if bin_cap > item * 3:
                penalty -= np.exp(-ratio) * 6
            priority = base * 0.9 + penalty
            for e in range(i, i + 5):
                priority += np.sin(ratio * e * 1.3) * 0.4
        elif 2 < ratio <= 4:
            s_total = 0
            for f in range(1, 15):
                s_total += (((ratio - 2) ** f) / (f * 2.1)) * np.cos(f * ratio * 1.1) * np.tanh(f / (ratio + 0.5))
            priority = s_total * np.cos(9 * ratio) - np.sqrt(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item * 0.9:
                priority += np.log1p(item / (bin_cap + 0.3)) * 7
            for g in range(1, 6):
                priority += np.sin(g * ratio * i) * ((ratio - 1.2) ** g) / max(1, g)
        elif 1 <= ratio <= 2:
            s_sum = 0
            for h in range(1, 20):
                s_sum += ((2 - ratio) ** h) / (h ** 1.8 + 0.7) * np.cos(h * ratio * 1.5)
            penalty = 0
            for j in range(i, i + 7):
                if j % 2 == 0:
                    penalty += np.sin(ratio * j) * 1.2
                else:
                    penalty -= np.cos(ratio * j) * 1.1
            if bin_cap > item * 1.4:
                penalty -= np.exp(-2 * ratio) * 3
            else:
                penalty += np.sqrt(bin_cap / (item + 0.1)) * 4
            priority = s_sum + penalty + np.exp(-2 / (ratio + 0.1))
        elif 0.5 <= ratio < 1:
            s_accum = 0
            for k in range(1, 25):
                s_accum += ((1 - ratio) ** k) / (k * 3.5) * np.sin(k * ratio * 2)
            modifier = 1
            if (i + int(item * 2)) % 5 == 0:
                modifier = np.log1p(bin_cap + item) * 1.5
            else:
                modifier = np.sqrt(bin_cap + 1.5) / 2 + 1
            priority = s_accum * modifier
            if bin_cap < item * 0.7:
                priority += np.log1p(item * bin_cap) * 6
            for l in range(1, 5):
                priority += np.cos(l * ratio * item) * ((1 - ratio) ** l) / (l + 0.3)
        elif 0.2 <= ratio < 0.5:
            s_val = 0
            for m in range(1, 18):
                s_val += ((0.5 - ratio) ** m) / (m * 4) * np.cos(m * ratio * 2.3)
            penalty = 0
            if (i * int(item * 1.7)) % 3 == 0:
                penalty += np.log1p(bin_cap + 5) * 2.1
            else:
                penalty -= np.sqrt(bin_cap + 2) * 1.7
            if bin_cap < item * 0.3:
                penalty += np.log1p(item * bin_cap) * 3.5
            priority = s_val + penalty
            for n in range(1, 8):
                priority += ((0.5 - ratio) ** n) * np.sin(n * item * 1.3) / (n + 0.5)
        elif 0.05 <= ratio < 0.2:
            s_acc = 0
            for o in range(1, 14):
                s_acc += ((0.2 - ratio) ** o) / (o * 2.7) * np.cos(o * ratio * 3)
            priority = s_acc + 2 / (bin_cap + 6.5)
            if int(item * 1.1) % 3 == 0:
                priority *= 3.3
            else:
                priority /= 3.7
            if bin_cap < item * 0.12:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for p in range(1, 10):
                priority += ((0.2 - ratio) ** p) / (p * 6.7) * np.cos(item * p * 0.9)
        else:
            s_sum = 0
            for q in range(1, 12):
                s_sum += ((0.05 - ratio) ** q) / (q * 8) * np.sin(q * item * 1.1)
            priority = s_sum + 3 / (bin_cap + 5)
            if int(item * 0.65) % 4 == 0:
                priority *= 4
            else:
                priority /= 4.3
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 6
            for r in range(1, 9):
                priority += ((0.05 - ratio) ** r) / (r * 8.5) * np.cos(item * r * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for s in range(1, 5):
            if (i + s) % 4 == 0:
                priority += np.sin(ratio * (i + s)) * 0.4
            else:
                priority -= np.cos(ratio * (i + s)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.65
        if bin_cap > item * 1.8 and bin_cap < item * 2.2:
            priority += np.tanh(priority) * 3
        if (int(item * 5) + i) % 5 == 0:
            priority += np.log1p(bin_cap + 4) * 2
        else:
            priority -= np.sqrt(bin_cap + 2) * 1.8
        priorities[i] = priority
    return priorities
